T = TypeVar('T', bound=Event)

class OptimisticConcurrencyError(Exception):
    """Raised when an append operation fails due to version conflict."""
    pass

class EventStore:
    """
    Simulates a persistent event store supporting append and optimistic concurrency.
    Using a dictionary for in-memory storage simulation.
    """
    def __init__(self):
        # Stores {aggregate_id: List[Event]}
        self._store: Dict[str, List[Event]] = {}

    def load(self, aggregate_id: str) -> List[Event]:
        """Loads all historical events for a given aggregate ID."""
        if aggregate_id not in self._store:
            return []
        # Return a copy to prevent external modification of the stored history
        return list(self._store[aggregate_id])

    def stream_version(self, aggregate_id: str) -> int:
        """Returns the current version (max event count - 1) for an aggregate ID."""
        if aggregate_id not in self._store or not self._store[aggregate_id]:
            return 0 # Version 0 means no events yet
        return len(self._store[aggregate_id])

    def append(self, aggregate_id: str, new_events: List[T], expected_version: int = None) -> int:
        """
        Appends a list of new events to an aggregate, enforcing optimistic concurrency.

        Args:
            aggregate_id: ID of the aggregate.
            new_events: List of new events (must be pre-filled with correct versions).
            expected_version: The version expected before appending. If None, reads current version first.

        Returns:
            The new stream version after successful append.

        Raises:
            OptimisticConcurrencyError: If the actual version does not match the expected version.
        """
        current_events = self._store.get(aggregate_id, [])
        actual_version = len(current_events)

        # 1. Check concurrency constraint
        if expected_version is not None and actual_version != expected_version:
            raise OptimisticConcurrencyError(
                f"Optimistic Concurrency Failure for {aggregate_id}. "
                f"Expected version {expected_version} but found version {actual_version}."
            )

        # 2. Process appending events (Assume new_events are already properly versioned to actual_version + 1, etc.)
        new_event_list: List[Event] = []
        for event in new_events:
             # Basic type safety check for demonstration purposes
            if not isinstance(event, Event):
                raise TypeError("All items in new_events must inherit from Event.")

            # Since we are simulating appending, the version should be sequential starting from actual_version + 1
            expected_ver = actual_version + len(new_event_list) + 1
            setattr(event, 'version', expected_ver) # Explicitly set for safety / consistency when using dataclasses

            new_event_list.append(event)


        # Add to store (Overwrite/Initialize list if necessary, otherwise append)
        if aggregate_id not in self._store:
            self._store[aggregate_id] = []

        self._store[aggregate_id].extend(new_event_list)

        return len(self._store[aggregate_id])

    def __repr__(self):
        return f"<EventStore (Simulated Storage)>"

