class Projection(ABC):
    """Abstract base class for projections (read models)."""
    def __init__(self, aggregate_id: str):
        self.aggregate_id = aggregate_id
        self._state = None

    @property
    def state(self):
        return self._state

    @classmethod
    @abstractmethod
    def build_initial_state(cls, event: Event) -> 'Projection':
        """Initializes the projection state based on a single foundational event."""
        # Subclasses must implement this. It typically handles AccountOpened logic.
        pass

    @abstractmethod
    def apply_event(self, event: Event) -> None:
        """Applies a single event to update the current state of the projection."""
        pass

    def rebuild(self, events: List[Event]):
        """Rebuilds the entire state by processing all historical events."""
        print(f"[{self.__class__.__name__}]: Rebuilding state for {self.aggregate_id} from {len(events)} events.")
        # Reset internal state representation
        self._state = None

        for event in events:
            # We assume the event stream is ordered chronologically (which EventStore guarantees)
            self.apply_event(event)


class BankAccount(Projection):
    """A specific projection modeling a bank account balance."""
    def __init__(self, aggregate_id: str):
        super().__init__(aggregate_id)
        # Internal state representation for the bank account
        self._state = {"balance": 0.0, "status": "CLOSED"}

    @classmethod
    def build_initial_state(cls, event: Event):
        """Handles mandatory initial setup, typically AccountOpened."""
        if not isinstance(event, type(AccountOpened)):
             raise TypeError("BankAccount initialization requires an AccountOpened event.")

        # Initialize the state object instance using the passed class.
        # Since we need to pass aggregate_id and account opened logic is key:
        instance = cls(event.aggregate_id)
        instance._state["balance"] = event.initial_balance
        instance._state["status"] = "OPEN"
        return instance

    def apply_event(self, event: Event):
        """Updates the state based on the received event."""
        if not isinstance(event, Event):
            raise TypeError("Event must inherit from Event.")

        # The crucial logic switch/case based on event type
        if event.__class__.__name__ == 'AccountOpened':
            # Handled implicitly during initialization rebuild, but kept robustly here.
            self._state["balance"] = event.initial_balance
            self._state["status"] = "OPEN"

        elif event.__class__.__name__ == 'Deposited':
            if self._state["status"] != "OPEN":
                 raise Exception("Cannot deposit: Account is closed.")
            self._state["balance"] += event.amount

        elif event.__class__.__name__ == 'Withdrawn':
            if self._state["status"] != "OPEN":
                 raise Exception("Cannot withdraw: Account is closed.")
            if event.amount > self._state["balance"]:
                raise Exception("Insufficient funds for withdrawal.")
            self._state["balance"] -= event.amount

        elif event.__class__.__name__ == 'AccountClosed':
            self._state["status"] = "CLOSED"

        else:
            # Ignore unknown events gracefully or raise an error, depending on policy.
            print(f"Warning: Unknown event type {event.__class__.__name__} encountered.")


    @property
    def balance(self):
        return self._state["balance"]

    @property
    def status(self):
        return self._state["status"]

